#!/usr/bin/env python3
# MedBoard Pro — B5 generation-cap deploy (bulk-only)
# Adds per-(exam_level,topic) saturation budget to scripts/bulk-generate.js.
# Idempotent (sentinel: fetchTopicBudgets). All-or-nothing: aborts before any
# write unless every anchor matches exactly once.
import base64, sys, pathlib

PATH = "scripts/bulk-generate.js"
OLD_FUNC  = base64.b64decode("").decode("utf-8")
NEW_BLOCK = base64.b64decode("").decode("utf-8")
MAIN_OLD  = "  const queue   = buildWorkQueue(TARGET_COUNT);"
MAIN_NEW  = "  const _budgets = await fetchTopicBudgets();\n  const queue   = buildWorkQueue(TARGET_COUNT, _budgets);"

p = pathlib.Path(PATH)
if not p.exists():
    sys.exit("ABORT: %s not found (run from repo root)" % PATH)
src = p.read_text(encoding="utf-8")

if "fetchTopicBudgets" in src:
    print("Already patched (sentinel fetchTopicBudgets present) — no change.")
    sys.exit(0)

n_func = src.count(OLD_FUNC)
n_main = src.count(MAIN_OLD)
if n_func != 1:
    sys.exit("ABORT: buildWorkQueue anchor matched %d times (expected 1)." % n_func)
if n_main != 1:
    sys.exit("ABORT: main() call anchor matched %d times (expected 1)." % n_main)

src = src.replace(OLD_FUNC, NEW_BLOCK, 1)
src = src.replace(MAIN_OLD, MAIN_NEW, 1)
p.write_text(src, encoding="utf-8")
print("OK: B5 generation cap applied to %s" % PATH)
print("   - inserted GEN_CAP constants + async fetchTopicBudgets()")
print("   - replaced buildWorkQueue with budget-aware (count, budgets) version")
print("   - main(): awaits fetchTopicBudgets() and passes budgets into buildWorkQueue")
print("Tunable env: GEN_CAP_CEILING (default 8; <=0 disables), GEN_CAP_EXEMPT (pipe-delimited).")
